import { useState } from "react";
import "./App.css";
import Cart from "./Cart";

function App() {
  const [page, setPage] = useState("home");
  const [cartItems, setCartItems] = useState([]);
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <div>
      <Header
        setPage={setPage}
        cartItems={cartItems}
        menuOpen={menuOpen}
        setMenuOpen={setMenuOpen}
      />

      {page === "home" && <Home setPage={setPage} />}

      {page === "delivery" && <DeliveryAreas />}

      {page === "contact" && <ContactUs />}

      {page === "fitness" && (
        <FitnessPage
          cartItems={cartItems}
          setCartItems={setCartItems}
          setPage={setPage}
        />
      )}

      {page === "cart" && (
        <Cart
          cartItems={cartItems}
          setCartItems={setCartItems}
          setPage={setPage}
        />
      )}

      <Footer />
    </div>
  );
}

/* HEADER */

function Header({
  setPage,
  cartItems,
  menuOpen,
  setMenuOpen,
}) {
  const cartCount = cartItems.reduce(
    (sum, item) => sum + item.quantity,
    0
  );

  const goToPage = (pageName) => {
    setPage(pageName);
    setMenuOpen(false);
  };

  return (
    <>
      <header className="header">
        <div
          className="logo"
          onClick={() => goToPage("home")}
        >
          RentNest
        </div>

        <nav>
          <a onClick={() => goToPage("home")}>
            HOME
          </a>

          <a onClick={() => goToPage("delivery")}>
            DELIVERY AREAS
          </a>

          <a onClick={() => goToPage("contact")}>
            CONTACT US
          </a>

          <a onClick={() => goToPage("cart")}>
            CART ({cartCount})
          </a>
        </nav>

        <div className="header-right">
          <div className="phone">
            📞 0800 111 313
          </div>

          <button
            className="menu-btn"
            onClick={() => setMenuOpen(true)}
          >
            ☰
          </button>
        </div>
      </header>

      {menuOpen && (
        <div className="menu-overlay">
          <div className="side-menu">
            <button
              className="close-btn"
              onClick={() => setMenuOpen(false)}
            >
              ×
            </button>

            <h1>RentNest</h1>

            <input placeholder="Search products..." />

            <p onClick={() => goToPage("home")}>
              Home
            </p>

            <p onClick={() => goToPage("delivery")}>
              Delivery Areas
            </p>

            <p onClick={() => goToPage("contact")}>
              Contact Us
            </p>

            <p onClick={() => goToPage("cart")}>
              Cart ({cartCount})
            </p>

            <h2>📞 0800 111 313</h2>
          </div>
        </div>
      )}
    </>
  );
}

/* HOME */

function Home({ setPage }) {
  return (
    <>
      <section className="features">
        <div>↩️ Flexible Rental</div>

        <div>💲 Affordable Solutions</div>

        <div>✅ Fast Approval</div>

        <div>🔧 Replace or Repair</div>
      </section>

      <section className="hero">
        <div>
          <h1>
            New Zealand's Trusted Rental
            Solution
          </h1>

          <button
            onClick={() => setPage("fitness")}
          >
            SHOP FITNESS
          </button>

          <button
            onClick={() => setPage("cart")}
            style={{
              marginLeft: "15px",
              background: "#52796f",
            }}
          >
            VIEW CART
          </button>
        </div>

        <div className="hero-text">
          <p>
            Rent furniture, appliances and
            fitness equipment easily.
          </p>

          <p>
            Fast delivery, affordable weekly
            prices and flexible rentals.
          </p>
        </div>
      </section>
    </>
  );
}

/* FITNESS */

function FitnessPage({
  cartItems,
  setCartItems,
  setPage,
}) {
  const products = [
    {
      id: 1,
      name: "Exercise Bike",
      priceNumber: 14,
      img: "https://images.unsplash.com/photo-1591741547934-8d7c16ff8e3b?auto=format&fit=crop&w=500&q=80",
      desc:
        "Fitness bike with adjustable resistance.",
    },

    {
      id: 2,
      name: "Treadmill",
      priceNumber: 22,
      img: "https://images.unsplash.com/photo-1576678927484-cc907957088c?auto=format&fit=crop&w=500&q=80",
      desc:
        "Treadmill with speed and incline controls.",
    },

    {
      id: 3,
      name: "Cross Trainer",
      priceNumber: 18,
      img: "https://images.unsplash.com/photo-1517963879433-6ad2b056d712?auto=format&fit=crop&w=500&q=80",
      desc:
        "Full body workout cross trainer.",
    },

    {
      id: 4,
      name: "Rower",
      priceNumber: 15,
      img: "https://images.unsplash.com/photo-1599058917212-d750089bc07e?auto=format&fit=crop&w=500&q=80",
      desc:
        "Rowing machine for cardio training.",
    },
  ];

  const addToCart = (product) => {
    const exists = cartItems.find(
      (item) => item.id === product.id
    );

    if (exists) {
      setCartItems(
        cartItems.map((item) =>
          item.id === product.id
            ? {
                ...item,
                quantity: item.quantity + 1,
              }
            : item
        )
      );
    } else {
      setCartItems([
        ...cartItems,
        { ...product, quantity: 1 },
      ]);
    }

    setPage("cart");
  };

  return (
    <>
      <section className="shop-banner">
        <h1>Shop</h1>
      </section>

      <section className="fitness-intro">
        <p>Home / Fitness</p>

        <h1>Fitness Equipment</h1>
      </section>

      <section className="fitness-products">
        <div className="product-grid">
          {products.map((item) => (
            <div
              className="product"
              key={item.id}
            >
              <div className="product-image-box">
                <img
                  src={item.img}
                  alt={item.name}
                />

                <p>{item.desc}</p>
              </div>

              <h2>{item.name}</h2>

              <h3>
                $
                {item.priceNumber.toFixed(2)}
                <span> per week *</span>
              </h3>

              <button
                className="cart-btn"
                onClick={() => addToCart(item)}
              >
                ADD TO CART
              </button>
            </div>
          ))}
        </div>
      </section>
    </>
  );
}

/* DELIVERY */

function DeliveryAreas() {
  return (
    <>
      <section className="delivery-hero">
        <h1>Delivery Areas</h1>
      </section>

      <section className="delivery-page">
        <div className="callback-form">
          <h2>Request a callback</h2>

          <div className="form-row">
            <input placeholder="First Name" />

            <input placeholder="Last Name" />
          </div>

          <div className="form-row">
            <input placeholder="Email" />

            <input placeholder="Phone" />
          </div>

          <label>
            When would you like us to call?
          </label>

          <div className="checkbox-row">
            <label>
              <input type="checkbox" />
              Morning
            </label>

            <label>
              <input type="checkbox" />
              Afternoon
            </label>

            <label>
              <input type="checkbox" />
              Night
            </label>
          </div>

          <input placeholder="Post Code or Suburb" />

          <input placeholder="Please select most relevant topic for your enquiry" />

          <input placeholder="Please select one" />

          <textarea placeholder="Message"></textarea>

          <button>SUBMIT NOW</button>
        </div>

        <div className="map-section">
          <div className="map-title-row">
            <h2>
              📍 Find Your Delivery Region
            </h2>

            <input placeholder="Post Code or Suburb" />
          </div>

          <iframe
            title="map"
            src="https://www.google.com/maps?q=New%20Zealand&output=embed"
            width="100%"
            height="560"
            style={{ border: 0 }}
          ></iframe>
        </div>
      </section>
    </>
  );
}

/* CONTACT */

function ContactUs() {
  return (
    <section className="contact-page">
      <h1>Contact Us</h1>

      <p>📞 0800 111 313</p>

      <p>Email: info@rentnest.co.nz</p>
    </section>
  );
}

/* FOOTER */

function Footer() {
  return (
    <footer>
      <div>
        <h2>
          Want to know more about our
          rentals?
        </h2>

        <h2>Join our mailing list!</h2>

        <input placeholder="First Name" />

        <input placeholder="Email Address" />

        <button>SUBSCRIBE</button>
      </div>

      <div>
        <h3>Pages</h3>

        <p>Home</p>

        <p>Delivery Areas</p>

        <p>Contact Us</p>

        <p>Cart</p>
      </div>

      <div>
        <h3>Get In Touch</h3>

        <p>📞 0800 111 313</p>
      </div>
    </footer>
  );
}

export default App;
